package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsCommentMarkerSet_ReturnsFalse_WhenCommentMarkerIsNull() {
        // CSVFormat is immutable, so we create a new instance with commentMarker null using withCommentMarker(null)
        csvFormat = csvFormat.withCommentMarker((Character) null);

        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_ReturnsTrue_WhenCommentMarkerIsSet() {
        // Use withCommentMarker to set commentMarker to a non-null value
        csvFormat = csvFormat.withCommentMarker('#');

        assertTrue(csvFormat.isCommentMarkerSet());
    }
}
